import{_ as t}from"./chunks/demo-main.CMXJB1uW.js";import{_ as e}from"./chunks/demo-doc.NIuiqrK9.js";import{_ as o}from"./chunks/demo-iframe.Cbz061mf.js";import{c,Q as a,j as r,m as i}from"./chunks/framework.BkjtU8k0.js";const k=JSON.parse('{"title":"Demo 说明","description":"","frontmatter":{},"headers":[],"relativePath":"guide/demo.md","filePath":"guide/demo.md","lastUpdated":1779263197000}'),s={name:"guide/demo.md"};function l(p,d,h,n,m,b){return a(),r("div",null,[...d[0]||(d[0]=[i('<h1 id="demo-说明" tabindex="-1">Demo 说明 <a class="header-anchor" href="#demo-说明" aria-label="Permalink to &quot;Demo 说明&quot;">​</a></h1><div class="doc-kicker">See It Before You Ship It</div><p class="doc-lead"> 一个好用的 Demo，不只是“给别人看看”，也是团队内部确认能力边界、联调文件样本和复现问题的最快入口。 当前仓库已经为所有已注册格式准备了可切换入口，适合在本地开发、依赖升级和上线前做完整回归。 </p><h2 id="本地可用的两个入口" tabindex="-1">本地可用的两个入口 <a class="header-anchor" href="#本地可用的两个入口" aria-label="Permalink to &quot;本地可用的两个入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>入口</th><th>地址</th><th>适合做什么</th></tr></thead><tbody><tr><td>主示例页</td><td><code>/</code></td><td>切换预置文件、上传本地文件、快速确认各类格式表现</td></tr><tr><td>iframe 示例页</td><td><code>/example/embedded.html</code></td><td>验证独立部署与二进制推送协议</td></tr><tr><td>适配层 Demo</td><td><code>packages/demo</code></td><td>同时验证 React 组件和纯 JS helper 的私有化 iframe 集成</td></tr></tbody></table><h2 id="主示例页" tabindex="-1">主示例页 <a class="header-anchor" href="#主示例页" aria-label="Permalink to &quot;主示例页&quot;">​</a></h2><p>主示例页内置了完整示例列表，包括 Word、Excel、PPT、PDF、OFD、DXF、Excalidraw、draw.io、EPUB、UMD、Markdown、代码/文本、图片、音频与视频。示例选择器按文件类型分组展示，每个样例都提供图标、格式名和文件名，点击后会立即打开并自动收起选择器。它适合做三件事:</p><ul><li>快速演示当前项目支持哪些文件类型</li><li>用本地上传验证 <code>file</code> 方案</li><li>在修改渲染逻辑后做肉眼回归检查</li></ul><div class="doc-shot"><img src="'+t+'" alt="主示例页截图"><p class="doc-caption">主示例页提供分组样例文件盒子、URL 预览和上传预览，是最直接的联调入口。</p></div><h2 id="word-页面效果" tabindex="-1">Word 页面效果 <a class="header-anchor" href="#word-页面效果" aria-label="Permalink to &quot;Word 页面效果&quot;">​</a></h2><p>Word 示例被单独拿出来说明，因为它已经不只是“能打开”，而是具备更明确的页面感。<code>.doc</code> 和 <code>.docx</code> 都会尽量保留灰色页面底、白色纸张、页面居中和宽度自适应的阅读体验。</p><div class="doc-shot"><img src="'+e+'" alt="DOC 文件渲染截图"><p class="doc-caption">Word 文件会显示在灰色工作台中的白色纸张上，页面居中，阅读体验更接近真实文档。</p></div><h2 id="iframe-示例页" tabindex="-1">iframe 示例页 <a class="header-anchor" href="#iframe-示例页" aria-label="Permalink to &quot;iframe 示例页&quot;">​</a></h2><p><code>public/example/embedded.html</code> 演示了宿主页面如何下载文件，再把 <code>Blob</code> 推送给预览器。</p><div class="doc-shot"><img src="'+o+`" alt="Iframe 示例页截图"><p class="doc-caption">iframe 示例适合验证跨系统集成路径，尤其适合做带鉴权文件的联调。</p></div><h2 id="react-纯-js-适配层-demo" tabindex="-1">React / 纯 JS 适配层 Demo <a class="header-anchor" href="#react-纯-js-适配层-demo" aria-label="Permalink to &quot;React / 纯 JS 适配层 Demo&quot;">​</a></h2><p>仓库中的 <code>packages/demo</code> 会把 <code>packages/web/viewer</code> 同步到自己的 <code>public/file-viewer</code>，页面上同时挂载 React 组件和纯 JS helper。调试时运行:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev:adapters</span></span></code></pre></div><p>构建上线前运行:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:adapter-demo</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @flyfish-group/file-viewer-demo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preview</span></span></code></pre></div><p>如果开发服务和 build preview 中两个面板都能显示同一份 Markdown 示例，就说明 npm 包默认的 <code>/file-viewer/index.html</code> 私有化路径可用。</p><h2 id="示例文件清单" tabindex="-1">示例文件清单 <a class="header-anchor" href="#示例文件清单" aria-label="Permalink to &quot;示例文件清单&quot;">​</a></h2><p>仓库中当前提供的示例文件位于 <code>public/example/</code>:</p><p>代码、配置和日志类样本已经按真实集成场景扩充，不再只是几行占位内容；它们会覆盖注释、函数、类型、嵌套配置、SQL CTE、Shell 参数、diff 块和长内容滚动，适合验证代码高亮的实际可读性。CAD、绘图、音频和 EPUB 样本使用公开文件，UMD 电子书样本由项目内生成，来源记录在 <code>public/example/SOURCES.md</code>。</p><table tabindex="0"><thead><tr><th>文件</th><th>用途</th><th>对应能力</th></tr></thead><tbody><tr><td><code>test.doc</code></td><td>验证老 Word 文档链路</td><td><code>doc</code> + Word 风格页面容器</td></tr><tr><td><code>word.docx</code></td><td>验证现代 Word 文档</td><td><code>docx</code></td></tr><tr><td><code>excel.xlsx</code></td><td>验证表格样式链路</td><td><code>xlsx</code></td></tr><tr><td><code>excel.xlsm</code></td><td>验证宏工作簿扩展名映射</td><td><code>xlsm</code></td></tr><tr><td><code>excel.xlsb</code></td><td>验证二进制工作簿扩展名映射</td><td><code>xlsb</code></td></tr><tr><td><code>excel.xls</code></td><td>验证老 Excel 扩展名映射</td><td><code>xls</code></td></tr><tr><td><code>table.csv</code></td><td>验证轻量数据表格链路</td><td><code>csv</code></td></tr><tr><td><code>excel.ods</code></td><td>验证 OpenDocument 表格扩展名映射</td><td><code>ods</code></td></tr><tr><td><code>excel.fods</code></td><td>验证 Flat ODS 扩展名映射</td><td><code>fods</code></td></tr><tr><td><code>excel.numbers</code></td><td>验证 Numbers 扩展名映射</td><td><code>numbers</code></td></tr><tr><td><code>ppt.pptx</code></td><td>验证演示文稿渲染、组合图形、主题背景和图片资源</td><td><code>pptx</code></td></tr><tr><td><code>pdf.pdf</code></td><td>验证 PDF 阅读体验、缩放工具栏和页面导航窗格</td><td><code>pdf</code></td></tr><tr><td><code>ofd.ofd</code></td><td>验证 OFD 在线预览</td><td><code>ofd</code></td></tr><tr><td><code>drawing.dxf</code></td><td>使用公开 DXF 样例验证 CAD 图纸预览、平移、缩放和图层控制</td><td><code>dxf</code></td></tr><tr><td><code>sample.dwg</code></td><td>使用公开 DWG 样例验证 DWG 兼容提示</td><td><code>dwg</code></td></tr><tr><td><code>flow.excalidraw</code></td><td>使用公开 Excalidraw 图纸验证官方恢复与 SVG 导出预览</td><td><code>excalidraw</code></td></tr><tr><td><code>process.drawio</code></td><td>使用官方 draw.io 示例验证 diagrams.net Viewer 预览</td><td><code>drawio</code></td></tr><tr><td><code>book.epub</code></td><td>使用 Project Gutenberg 公开 EPUB 验证电子书目录和滚动阅读</td><td><code>epub</code></td></tr><tr><td><code>book.umd</code></td><td>使用项目内生成的 UMD 电子书验证元数据、目录和 zlib 正文解析</td><td><code>umd</code></td></tr><tr><td><code>markdown.md</code></td><td>验证 Markdown 阅读样式</td><td><code>md</code></td></tr><tr><td><code>notes.markdown</code></td><td>验证 Markdown 长扩展名</td><td><code>markdown</code></td></tr><tr><td><code>text.txt</code></td><td>验证纯文本展示</td><td><code>txt</code></td></tr><tr><td><code>data.json</code></td><td>验证 JSON 高亮</td><td><code>json</code></td></tr><tr><td><code>code.js</code></td><td>验证 JavaScript 高亮</td><td><code>js</code></td></tr><tr><td><code>code.mjs</code></td><td>验证 ES Module JavaScript 高亮</td><td><code>mjs</code></td></tr><tr><td><code>code.cjs</code></td><td>验证 CommonJS JavaScript 高亮</td><td><code>cjs</code></td></tr><tr><td><code>code.ts</code></td><td>验证 TypeScript 高亮</td><td><code>ts</code></td></tr><tr><td><code>code.tsx</code></td><td>验证 TSX 高亮</td><td><code>tsx</code></td></tr><tr><td><code>code.jsx</code></td><td>验证 JSX 高亮</td><td><code>jsx</code></td></tr><tr><td><code>code.css</code></td><td>验证 CSS 高亮</td><td><code>css</code></td></tr><tr><td><code>page.html</code></td><td>验证 HTML 源码展示，不作为网页执行</td><td><code>html</code></td></tr><tr><td><code>page.htm</code></td><td>验证 HTM 源码展示，不作为网页执行</td><td><code>htm</code></td></tr><tr><td><code>data.xml</code></td><td>验证 XML 高亮</td><td><code>xml</code></td></tr><tr><td><code>component.vue</code></td><td>验证 Vue 单文件组件高亮</td><td><code>vue</code></td></tr><tr><td><code>config.yaml</code></td><td>验证 YAML 高亮</td><td><code>yaml</code></td></tr><tr><td><code>config.yml</code></td><td>验证 YML 高亮</td><td><code>yml</code></td></tr><tr><td><code>settings.ini</code></td><td>验证 INI 高亮</td><td><code>ini</code></td></tr><tr><td><code>script.sh</code></td><td>验证 Shell 脚本高亮</td><td><code>sh</code></td></tr><tr><td><code>script.bash</code></td><td>验证 Bash 脚本高亮</td><td><code>bash</code></td></tr><tr><td><code>query.sql</code></td><td>验证 SQL 高亮</td><td><code>sql</code></td></tr><tr><td><code>main.go</code></td><td>验证 Go 高亮</td><td><code>go</code></td></tr><tr><td><code>main.rs</code></td><td>验证 Rust 高亮</td><td><code>rs</code></td></tr><tr><td><code>index.php</code></td><td>验证 PHP 高亮</td><td><code>php</code></td></tr><tr><td><code>main.c</code></td><td>验证 C 高亮</td><td><code>c</code></td></tr><tr><td><code>main.cpp</code></td><td>验证 C++ 高亮</td><td><code>cpp</code></td></tr><tr><td><code>module.cc</code></td><td>验证 C++ 兼容扩展名高亮</td><td><code>cc</code></td></tr><tr><td><code>main.h</code></td><td>验证 C/C++ 头文件高亮</td><td><code>h</code></td></tr><tr><td><code>main.hpp</code></td><td>验证 C++ 头文件高亮</td><td><code>hpp</code></td></tr><tr><td><code>program.cs</code></td><td>验证 C# 高亮</td><td><code>cs</code></td></tr><tr><td><code>change.diff</code></td><td>验证 diff 高亮</td><td><code>diff</code></td></tr><tr><td><code>code.java</code></td><td>验证 Java 高亮</td><td><code>java</code></td></tr><tr><td><code>code.py</code></td><td>验证 Python 高亮</td><td><code>py</code></td></tr><tr><td><code>app.log</code></td><td>验证日志文本展示</td><td><code>log</code></td></tr><tr><td><code>pic.png</code></td><td>验证 PNG 图片预览</td><td><code>png</code></td></tr><tr><td><code>pic.jpg</code></td><td>验证 JPG 图片预览</td><td><code>jpg</code></td></tr><tr><td><code>pic.jpeg</code></td><td>验证 JPEG 图片预览</td><td><code>jpeg</code></td></tr><tr><td><code>pic.gif</code></td><td>验证 GIF 图片预览</td><td><code>gif</code></td></tr><tr><td><code>pic.bmp</code></td><td>验证 BMP 图片预览</td><td><code>bmp</code></td></tr><tr><td><code>pic.tiff</code></td><td>验证 TIFF 图片预览</td><td><code>tiff</code></td></tr><tr><td><code>pic.tif</code></td><td>验证 TIF 图片预览</td><td><code>tif</code></td></tr><tr><td><code>vector.svg</code></td><td>验证 SVG 图片预览</td><td><code>svg</code></td></tr><tr><td><code>pic.webp</code></td><td>验证 WEBP 图片预览</td><td><code>webp</code></td></tr><tr><td><code>audio.mp3</code></td><td>使用 MDN CC0 音频验证 MP3 原生播放</td><td><code>mp3</code></td></tr><tr><td><code>audio.ogg</code></td><td>使用 Wikimedia Commons 音频验证 OGG 原生播放</td><td><code>ogg</code></td></tr><tr><td><code>video.mp4</code></td><td>验证视频播放</td><td><code>mp4</code></td></tr></tbody></table><div class="doc-note"> 部分兼容格式示例复用了同一份可解析内容来覆盖扩展名入口，例如表格兼容格式和图片兼容格式。上线前仍建议使用业务真实文件补一轮回归。 </div><h2 id="完整覆盖与绘图说明" tabindex="-1">完整覆盖与绘图说明 <a class="header-anchor" href="#完整覆盖与绘图说明" aria-label="Permalink to &quot;完整覆盖与绘图说明&quot;">​</a></h2><p>上面的清单已经覆盖当前注册的全部扩展名。DWG 当前作为 CAD 兼容入口保留，打开 <code>.dwg</code> 时会提示转换为 DXF 后预览，不会把 GPL 授权的 DWG 解析运行时打进组件包。</p><p>Excalidraw 使用官方 <code>@excalidraw/excalidraw</code> 的 <code>restore</code> 补齐真实公开文件中常见的精简字段，再通过 <code>exportToSvg</code> 生成只读 SVG；draw.io / diagrams.net 文件使用官方 <code>GraphViewer</code> 渲染 mxGraphModel / mxfile。组件不自行实现绘图格式解析，只做按需加载、容器挂载和错误提示。</p><h2 id="公开样例来源" tabindex="-1">公开样例来源 <a class="header-anchor" href="#公开样例来源" aria-label="Permalink to &quot;公开样例来源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>示例</th><th>来源</th><th>许可</th></tr></thead><tbody><tr><td><code>drawing.dxf</code></td><td><code>mozman/ezdxf</code> 的 <code>examples_dxf/wipeout_door.dxf</code></td><td>MIT</td></tr><tr><td><code>sample.dwg</code></td><td><code>dshn06/cad-webviewer-unity</code> 的 <code>baseline-sample.dwg</code></td><td>MIT</td></tr><tr><td><code>flow.excalidraw</code></td><td><code>neo4j-labs/agent-memory</code> 的 <code>poleo-model.excalidraw</code></td><td>Apache-2.0</td></tr><tr><td><code>process.drawio</code></td><td><code>jgraph/drawio-diagrams</code> 的 <code>blog/data-flow.drawio</code></td><td>Apache-2.0</td></tr><tr><td><code>book.umd</code></td><td>项目内生成的最小 UMD 文本电子书 fixture</td><td>Apache-2.0</td></tr><tr><td><code>audio.mp3</code></td><td>MDN interactive examples 的 <code>t-rex-roar.mp3</code></td><td>CC0</td></tr><tr><td><code>audio.ogg</code></td><td>Wikimedia Commons 的 <code>Example.ogg</code></td><td>CC BY-SA 3.0</td></tr><tr><td><code>book.epub</code></td><td>Project Gutenberg 的 <code>Alice&#39;s Adventures in Wonderland</code> EPUB</td><td>Public domain in the USA</td></tr></tbody></table><p>这些样例的作用是验证预览器兼容性，不承诺覆盖你业务中所有 CAD 图元、绘图插件、UMD 方言或打包器输出。上线前仍建议把自己的高频文件加入回归清单。</p><h2 id="建议保留一套自己的回归样本" tabindex="-1">建议保留一套自己的回归样本 <a class="header-anchor" href="#建议保留一套自己的回归样本" aria-label="Permalink to &quot;建议保留一套自己的回归样本&quot;">​</a></h2><p>如果你要把这个项目接进正式业务，建议你把下面这几类文件各留一份，形成自己的最小回归集:</p><ul><li>一份版式复杂的 <code>docx</code></li><li>一份历史 <code>.doc</code></li><li>一份带合并单元格和颜色的 <code>xlsx</code></li><li>一份兼容格式表格，比如 <code>xls</code> 或 <code>csv</code></li><li>一份业务里最常见的 <code>pdf</code></li><li>一份真实 OFD 发票或归档件</li><li>一份 DXF 图纸</li><li>一份 Excalidraw 或 draw.io 图纸</li><li>一份 EPUB 或 UMD 电子书</li><li>一份 Markdown 说明文档</li><li>一份日志或配置文件，比如 <code>log</code> / <code>json</code></li><li>一份源码文件，比如 <code>ts</code> / <code>py</code> / <code>java</code></li><li>一份 <code>svg</code> 或 <code>webp</code> 图片</li><li>一份业务常用音频，比如 <code>mp3</code> 或 <code>ogg</code></li></ul><p>这样每次升级预览器、调整依赖或准备发版时，都能快速知道“这次有没有把关键能力碰坏”。</p><div class="doc-note"> 建议你先用仓库内置样本确认主链路，再用自己的真实文件补一轮回归。前者帮你判断“项目本身能不能跑”，后者帮你判断“它能不能真正接住你的业务”。 </div>`,37)])])}const w=c(s,[["render",l]]);export{k as __pageData,w as default};
